function bestTeamScore(scores, ages) {
    const players = ages.map((age, index) => [age, scores[index]]);
    players.sort((a, b) => a[0] - b[0] || a[1] - b[1]);

    const n = players.length;
    const dp = Array(n).fill(0);
    let bestScore = 0;

    for (let i = 0; i < n; i++) {
        dp[i] = players[i][1];
        for (let j = 0; j < i; j++) {
            if (players[i][1] >= players[j][1]) {
                dp[i] = Math.max(dp[i], dp[j] + players[i][1]);
            }
        }
        bestScore = Math.max(bestScore, dp[i]);
    }

    return bestScore;
}
```


    1. First, we create a new array/list (`players`) of pairs containing the players' ages and scores. 
2. Next, we sort the `players` array/list by age, followed by sorting by scores within the same age.
3. We create a `dp` array/list of length `n` (number of players) initializing it with 0.
4. Then, we iterate through each player in the sorted `players` array/list:
    a. Set `dp[i]` to the current player's score.
    b. Iterate through all previous players (0 to i-1) and check if the current player's score is greater or equal to the previous player's score. If true, set `dp[i]` to the maximum value between existing `dp[i]` and the sum of that previous player's DP value plus the current player's score.
    c. Update the `best_score` with the maximum of its current value and `dp[i]` for each player.
5. Lastly, return the `best_score` which represents the highest overall score of all possible basketball teams without conflicts.

